import { reactive } from 'vue'

/**
 * Yerel diyalog g├Čr├╝n├╝rl├╝─¤├╝ (`<ui-dialog v-model:open="dialog.open">`).
 * Tek bir reactive nesne d├Čner ŌĆö `open` ├Čzelli─¤i do─¤rudan `v-model:open` ile ba─¤lan─▒r (i├¦ i├¦e `ref` + `v-model` ref ├Čzelli─¤inin ezilmesini ├Čnler).
 * `const { open } = useDialog()` kullanmay─▒n; `open` reaktivitesi kopar ŌĆö nesneyi oldu─¤u gibi tutun (`const d = useDialog()` ŌåÆ `d.open`).
 * @param {boolean} [initial=false]
 */
export function useDialog(initial = false) {
  return reactive({
    open: !!initial,
    show() {
      this.open = true
    },
    hide() {
      this.open = false
    },
    toggle() {
      this.open = !this.open
    },
  })
}
