<template>
  <div
    :class="['ui-checkbox-group', `ui-checkbox-group--${normalizedVariant}`]"
    role="group"
    :aria-label="ariaLabel || undefined"
  >
    <slot />
  </div>
</template>

<script>
const VARIANTS = ['list', 'button', 'List', 'Button']

let cgCounter = 0

export default {
  name: 'CheckboxGroup',
  props: {
    /** Se├¦ili de─¤erler dizisi (ilkel kar┼¤─▒la┼¤t─▒rma). */
    modelValue: {
      type: Array,
      default: () => [],
    },
    /** `list` ŌĆö dikey liste; `button` ŌĆö yan yana kart se├¦enekleri (RadioGroup `button` ile ayn─▒ y├╝zey). */
    variant: {
      type: String,
      default: 'list',
      validator: (v) => VARIANTS.includes(v),
    },
    ariaLabel: {
      type: String,
      default: '',
    },
  },
  emits: ['update:modelValue'],
  data() {
    cgCounter += 1
    return { groupName: `ui-checkbox-group-${cgCounter}` }
  },
  computed: {
    normalizedVariant() {
      const v = (this.variant || 'list').toLowerCase()
      return v === 'button' ? 'button' : 'list'
    },
  },
  provide() {
    return {
      uiCheckboxGroup: this,
    }
  },
}
</script>
